#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>
#include <omp.h>

#include "common.h"

#ifdef TIMING
#include "timing.h"
#endif

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

static int do_verify = 0;

static struct option long_options[] = {

  {"input", 1, NULL, 'i'},
  {"size", 1, NULL, 's'},
  {"verify", 0, NULL, 'v'},
  {0,0,0,0}
};

static int omp_num_threads = 40;

void lud_omp(float *m, int matrix_dim);

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

// Mark main as static to avoid multiple definition linker error
static int main ( int argc, char *argv[] )
{
  printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);

  int matrix_dim = 32; 
  int opt, option_index=0;
  func_ret_t ret;
  const char *input_file = NULL;
  float *m, *mm;
  stopwatch sw;

  while ((opt = getopt_long(argc, argv, "::vs:i:", 
                            long_options, &option_index)) != -1 ) {
    switch(opt){
    case 'i':
      input_file = optarg;
      break;
    case 'v':
      do_verify = 1;
      break;
    case 's':
      matrix_dim = atoi(optarg);
      printf("Generate input matrix internally, size =%d\n", matrix_dim);
      break;
    case '?':
      fprintf(stderr, "invalid option\n");
      break;
    case ':':
      fprintf(stderr, "missing argument\n");
      break;
    default:
      fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
	      argv[0]);
      exit(EXIT_FAILURE);
    }
  }

  if ( (argc > optind) || (1 == optind)) {
    fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
    exit(EXIT_FAILURE);
  }

  if (input_file) {
    printf("Reading matrix from file %s\n", input_file);
    ret = create_matrix_from_file(&m, input_file, &matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix from file %s\n", input_file);
      exit(EXIT_FAILURE);
    }
  } 
  else if (matrix_dim) {
    printf("Creating matrix internally size=%d\n", matrix_dim);
    ret = create_matrix(&m, matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix internally size=%d\n", matrix_dim);
      exit(EXIT_FAILURE);
    }
  }
  else {
    printf("No input file specified!\n");
    exit(EXIT_FAILURE);
  }

  if (do_verify){
    printf("Before LUD\n");
    matrix_duplicate(m, &mm, matrix_dim);
  }

#ifdef TIMING
  gettimeofday(&tv_kernel_start, NULL);
#endif

  stopwatch_start(&sw);
  lud_omp(m, matrix_dim);
  stopwatch_stop(&sw);

#ifdef TIMING
  gettimeofday(&tv_kernel_end, NULL);
  tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
  kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

  printf("Time consumed(ms): %lf\n", 1000*get_interval_by_sec(&sw));

  if (do_verify){
    printf("After LUD\n");
    printf(">>>Verify<<<<\n");
    lud_verify(mm, m, matrix_dim); 
    free(mm);
  }

  free(m);

#ifdef TIMING
  printf("Exec: %f\n", kernel_time);
#endif

  return EXIT_SUCCESS;
}				


void lud_omp(float *m, int matrix_dim)
{
    int i, j, k;
    int offset;
    int num_blocks = matrix_dim / BLOCK_SIZE;
    if (matrix_dim % BLOCK_SIZE != 0) num_blocks++;

    omp_set_num_threads(omp_num_threads);

    for (offset = 0; offset < matrix_dim; offset += BLOCK_SIZE) {
        int block_size = BLOCK_SIZE;
        if (offset + BLOCK_SIZE > matrix_dim)
            block_size = matrix_dim - offset;

        // Diagonal block factorization
        for (i = 0; i < block_size; i++) {
            for (j = i; j < block_size; j++) {
                float sum = m[(offset + i)*matrix_dim + offset + j];
                for (k = 0; k < i; k++)
                    sum -= m[(offset + i)*matrix_dim + offset + k] * m[(offset + k)*matrix_dim + offset + j];
                m[(offset + i)*matrix_dim + offset + j] = sum;
            }
            for (j = i + 1; j < block_size; j++) {
                float sum = m[(offset + j)*matrix_dim + offset + i];
                for (k = 0; k < i; k++)
                    sum -= m[(offset + j)*matrix_dim + offset + k] * m[(offset + k)*matrix_dim + offset + i];
                m[(offset + j)*matrix_dim + offset + i] = sum / m[(offset + i)*matrix_dim + offset + i];
            }
        }

        if (offset + block_size >= matrix_dim)
            break;

        int perimeter_blocks = (matrix_dim - offset) / block_size - 1;
        if ((matrix_dim - offset) % block_size != 0)
            perimeter_blocks++;

        // Perimeter blocks update
        #pragma omp parallel for private(i,j,k) schedule(static)
        for (int b = 0; b < perimeter_blocks; b++) {
            int col_offset = offset + (b + 1)*block_size;
            int row_offset = offset + (b + 1)*block_size;

            // Update perimeter row blocks
            for (i = 0; i < block_size; i++) {
                for (j = 0; j < block_size; j++) {
                    float sum = m[(offset + i)*matrix_dim + col_offset + j];
                    for (k = 0; k < i; k++)
                        sum -= m[(offset + i)*matrix_dim + offset + k] * m[(offset + k)*matrix_dim + col_offset + j];
                    m[(offset + i)*matrix_dim + col_offset + j] = sum;
                }
            }

            // Update perimeter column blocks
            for (i = 0; i < block_size; i++) {
                for (j = 0; j < block_size; j++) {
                    float sum = m[(row_offset + i)*matrix_dim + offset + j];
                    for (k = 0; k < j; k++)
                        sum -= m[(row_offset + i)*matrix_dim + offset + k] * m[(offset + k)*matrix_dim + offset + j];
                    m[(row_offset + i)*matrix_dim + offset + j] = sum / m[(offset + j)*matrix_dim + offset + j];
                }
            }
        }

        if (offset + block_size >= matrix_dim)
            break;

        int internal_blocks = perimeter_blocks;

        // Internal blocks update
        #pragma omp parallel for collapse(2) private(i,j,k) schedule(static)
        for (int by = 0; by < internal_blocks; by++) {
            for (int bx = 0; bx < internal_blocks; bx++) {
                int row_offset = offset + (by + 1)*block_size;
                int col_offset = offset + (bx + 1)*block_size;

                for (i = 0; i < block_size; i++) {
                    for (j = 0; j < block_size; j++) {
                        float sum = 0.0f;
                        for (k = 0; k < block_size; k++) {
                            sum += m[(row_offset + i)*matrix_dim + offset + k] * m[(offset + k)*matrix_dim + col_offset + j];
                        }
                        m[(row_offset + i)*matrix_dim + col_offset + j] -= sum;
                    }
                }
            }
        }
    }
}
